CREATE TABLE IF NOT EXISTS "NotificationRecipient" ("id" TEXT PRIMARY KEY, "email" TEXT NOT NULL UNIQUE, "name" TEXT, "role" TEXT, "orderAlerts" BOOLEAN NOT NULL DEFAULT true, "shippingAlerts" BOOLEAN NOT NULL DEFAULT true, "enabled" BOOLEAN NOT NULL DEFAULT true, "createdAt" TIMESTAMP NOT NULL DEFAULT now(), "updatedAt" TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE IF NOT EXISTS "FulfillmentToken" ("id" TEXT PRIMARY KEY, "orderId" TEXT NOT NULL REFERENCES "Order"("id"), "tokenHash" TEXT NOT NULL UNIQUE, "purpose" TEXT NOT NULL DEFAULT 'SHIPMENT_CONFIRMATION', "expiresAt" TIMESTAMP NOT NULL, "usedAt" TIMESTAMP, "createdAt" TIMESTAMP NOT NULL DEFAULT now());
